import { FileDropZone } from "@/components/common/FileDropZone";
import {
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import type { Control } from "react-hook-form";
import type { CreateApplicationPayload, UpdateApplicationPayload } from "../../types/applications.types";

type ApplicationFormValues = CreateApplicationPayload | UpdateApplicationPayload;

export const FileInput = <T extends ApplicationFormValues = ApplicationFormValues>({
  control,
  onFileSelect,
  onFileClear,
  disabled = false,
  className,
}: {
  control: Control<T>;
  onFileSelect?: (file: File) => void;
  onFileClear?: () => void;
  disabled?: boolean;
  className?: string;
}) => {
  return (
    <FormField
      control={control}
      name={"resume" as any}
      render={({ field }) => (
        <FormItem className={className}>
          <FormLabel>Resume</FormLabel>
          <FormControl>
            <FileDropZone
              acceptedTypes={[
                "application/pdf",
                "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
              ]}
              onFileSelect={(file: File) => {
                field.onChange(file);
                onFileSelect?.(file);
              }}
              onFileClear={() => {
                field.onChange(undefined);
                onFileClear?.();
              }}
              disabled={disabled}
              label="Upload Resume"
              description="PDF or DOCX (max 5MB)"
            />
          </FormControl>
          <FormMessage />
        </FormItem>
      )}
    />
  );
};
